const body = $('Webhook').item.json.body || {};
const figmaUrl = body.figma_url || '';

// Extract file key from Figma URL
// Format: https://www.figma.com/file/FILEKEY/name or https://www.figma.com/design/FILEKEY/name
const match = figmaUrl.match(/figma\.com\/(?:file|design)\/([a-zA-Z0-9]+)/);
const fileKey = match ? match[1] : body.file_key || '';

if (!fileKey) {
  return [{ json: { error: 'No Figma file key found. Send POST with { "figma_url": "https://figma.com/file/KEY/name" } or { "file_key": "KEY" }' } }];
}

return [{ json: { fileKey, figmaUrl } }];

const fs = require('fs');
const path = require('path');

const PROJECT = '/mnt/d/NAS-DATA/antenna-engine';

// Read current index.css
let currentCss = '';
try {
  currentCss = fs.readFileSync(path.join(PROJECT, 'src/index.css'), 'utf8');
} catch { currentCss = '// FILE NOT FOUND'; }

// Get Figma data from both HTTP nodes
let stylesData = '{}';
let fileData = '{}';
try {
  stylesData = JSON.stringify($('Figma Get Styles').item.json, null, 2);
} catch { stylesData = '{ "error": "styles not available" }'; }
try {
  fileData = JSON.stringify($('Figma Get File').item.json, null, 2).substring(0, 10000);
} catch { fileData = '{ "error": "file not available" }'; }

return [{ json: { currentCss, stylesData, fileData, fileKey: $('Parse Figma URL').item.json.fileKey } }];

const { execSync } = require('child_process');
const fs = require('fs');
const path = require('path');

const PROJECT = '/mnt/d/NAS-DATA/antenna-engine';
const output = $('Map Figma Tokens').item.json.output || '';

// Extract file block
const fileMatch = output.match(/<file path="([^"]+)">\n?([\s\S]*?)<\/file>/);
const reportMatch = output.match(/<report>\n?([\s\S]*?)<\/report>/);

let writeResult = 'No file block found';
if (fileMatch) {
  const filePath = path.join(PROJECT, fileMatch[1]);
  fs.writeFileSync(filePath, fileMatch[2].trim());
  writeResult = `Written: ${fileMatch[1]} (${fileMatch[2].length} chars)`;
}

const report = reportMatch ? reportMatch[1].trim() : 'No report generated';

// TSC Check
let tscResult = '';
try {
  tscResult = execSync('npx tsc --noEmit 2>&1', { cwd: PROJECT, timeout: 120000 }).toString();
  if (!tscResult.trim()) tscResult = 'OK - no errors';
} catch (e) {
  tscResult = e.stdout?.toString() || e.message;
}

// Git commit if TSC passes
let gitResult = '';
if (tscResult.includes('OK - no errors') || !tscResult.includes('error TS')) {
  try {
    execSync('git add -A', { cwd: PROJECT });
    execSync(`git commit -m "style: import Figma design tokens\n\nExtracted color, typography, shadow tokens from Figma.\nUpdated index.css @theme block."`, { cwd: PROJECT });
    execSync('git push origin main', { cwd: PROJECT });
    gitResult = 'Committed and pushed';
  } catch (e) {
    gitResult = `Git: ${e.message}`;
  }
} else {
  gitResult = 'Skipped commit — TSC errors';
}

return [{ json: { writeResult, report, tscResult, gitResult, figmaFileKey: $('Parse Figma URL').item.json.fileKey } }];
